// src/pages/Dashboard.js
import React, { useEffect, useMemo, useState } from "react";
import { createVehicle, listVehicles } from "../services/api";
import "./dashboard.css";

export default function Dashboard() {
  // form state
  const [licensePlate, setLicensePlate] = useState("");
  const [status, setStatus] = useState("active");

  // ui state
  const [loading, setLoading] = useState(false);
  const [note, setNote] = useState("");

  // data state
  const [vehicles, setVehicles] = useState([]);

  // fetch vehicles on first render
  useEffect(() => {
    let active = true;
    const run = async () => {
      try {
        const data = await listVehicles();
        if (active) setVehicles(Array.isArray(data) ? data : data?.items ?? []);
      } catch (err) {
        console.error(err);
        if (active) setNote("Failed to load vehicles");
      }
    };
    run();
    return () => {
      active = false;
    };
  }, []);

  // derived stats
  const stats = useMemo(() => {
    const total = vehicles.length;
    const active = vehicles.filter(v => v.status === "active").length;
    const idle = vehicles.filter(v => v.status === "idle").length;
    const maintenance = vehicles.filter(v => v.status === "maintenance").length;
    return { total, active, idle, maintenance };
  }, [vehicles]);

  const resetForm = () => {
    setLicensePlate("");
    setStatus("active");
  };

  const refreshVehicles = async () => {
    try {
      const data = await listVehicles();
      setVehicles(Array.isArray(data) ? data : data?.items ?? []);
    } catch (e) {
      console.error(e);
    }
  };

  const handleAdd = async () => {
    setNote("");
    if (!licensePlate.trim()) {
      setNote("License plate is required");
      return;
    }
    setLoading(true);
    try {
      await createVehicle({
        licensePlate: licensePlate.trim(),
        status,
      });
      setNote("Vehicle added");
      resetForm();
      await refreshVehicles();
    } catch (err) {
      console.error(err);
      const msg =
        err?.response?.data?.message ||
        err?.response?.data ||
        err?.message ||
        "Failed to add vehicle";
      setNote(String(msg));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="dash-wrap">
      <h1 className="dash-title">Dashboard</h1>

      {/* Stats */}
      <section className="stats-grid">
        <div className="card stat">
          <div className="stat-value">{stats.total}</div>
          <div className="stat-label">Vehicles</div>
        </div>
        <div className="card stat">
          <div className="stat-value">{stats.active}</div>
          <div className="stat-label">Active</div>
        </div>
        <div className="card stat">
          <div className="stat-value">{stats.idle + stats.maintenance}</div>
          <div className="stat-label">Idle + Maint.</div>
        </div>
      </section>

      {/* Main grid */}
      <section className="dash-grid">
        <div className="card">
          <h3 className="card-title">Live Vehicles</h3>
          {vehicles.length === 0 ? (
            <p className="muted">No vehicles</p>
          ) : (
            <ul className="list">
              {vehicles.map(v => (
                <li key={v.id || v.licensePlate}>
                  {v.licensePlate} — {v.status}
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="card">
          <h3 className="card-title">Add Vehicle</h3>

          <div className="form-row">
            <label className="label">License Plate</label>
            <input
              className="input"
              placeholder="KA-01-AB-1234"
              value={licensePlate}
              onChange={(e) => setLicensePlate(e.target.value)}
            />
          </div>

          <div className="form-row">
            <label className="label">Status</label>
            <select
              className="input"
              value={status}
              onChange={(e) => setStatus(e.target.value)}
            >
              <option value="active">active</option>
              <option value="idle">idle</option>
              <option value="maintenance">maintenance</option>
            </select>
          </div>

          <button className="btn-primary" onClick={handleAdd} disabled={loading}>
            {loading ? "Adding..." : "Add"}
          </button>

          {note && <p className="note">{note}</p>}
        </div>

        <div className="card wide">
          <h3 className="card-title">Map</h3>
          <div className="map-placeholder">Map placeholder (render markers here later)</div>
        </div>

        <div className="card">
          <h3 className="card-title">Analytics</h3>
          <ul className="list">
            <li>Active: {stats.active}</li>
            <li>Idle: {stats.idle}</li>
            <li>Maintenance: {stats.maintenance}</li>
          </ul>
        </div>
      </section>
    </div>
  );
}
